const sd = $getWorkflowStaticData('global');
sd.kampagnenZaehler = (sd.kampagnenZaehler || 0) + 1;
const setup = $('⚙️ Setup').first().json;

// Kampagnen-Typ rotiert automatisch - jede Kampagne fuehlt sich anders an
const typen = [
  { name: 'Flash-Sale', idee: '48h-Blitzangebot mit dem Rabattcode, harte Deadline, Countdown-Gefuehl' },
  { name: 'Bestseller-Spotlight', idee: 'Das beliebteste Produkt feiern: warum es alle lieben, Social-Proof-Gefuehl, Code als Bonus' },
  { name: 'Insider-Tipp', idee: 'Wertvoller Nischen-Tipp im Zentrum (echter Mehrwert!), Produkt nur elegant nebenbei, Code als Belohnung fuers Lesen' },
  { name: 'Geheimer Sale', idee: 'Nur-fuer-Abonnenten-Deal: exklusiv, verknappt, "nicht auf der Website beworben"' },
  { name: 'Neuheiten-Drop', idee: 'Neuste Produkte wie einen Launch inszenieren, Erste-sein-Gefuehl, Code fuer Early Birds' }
];
const typ = typen[(sd.kampagnenZaehler - 1) % typen.length];

const produkte = (($('🛍️ Produkte holen').first().json.products) || [])
  .slice(0, 15)
  .map(p => '- ' + p.title + ' (' + setup.SHOP_URL + '/products/' + p.handle + ', ' + (((p.variants || [])[0] || {}).price || '?') + ')');

const prompt = 'Du bist E-Mail-Marketing-Profi fuer den Onlineshop "' + setup.SHOP_NAME + '" (Nische: ' + setup.SHOP_NISCHE + ', Zielgruppe: ' + setup.ZIELGRUPPE + ').\n\n' +
  'KAMPAGNEN-TYP heute: ' + typ.name + ' -> ' + typ.idee + '\n' +
  'Rabattcode: ' + setup.KAMPAGNEN_RABATT_CODE + ' (' + setup.RABATT_PROZENT + '%)\n\n' +
  'Produktkatalog (Auszug):\n' + produkte.join('\n') + '\n\n' +
  'Schreibe die komplette Kampagnen-E-Mail auf Deutsch (Du-Form):\n' +
  '- Betreff: maximal 45 Zeichen, neugierig machend, zum Kampagnen-Typ passend\n' +
  '- Der Platzhalter {{VORNAME}} soll im HTML genau einmal fuer die persoenliche Anrede stehen\n' +
  '- 1-2 konkrete Produkte aus dem Katalog mit Links einbauen\n' +
  '- EIN klarer CTA-Button (als <a> mit Inline-Button-Styling)\n' +
  '- Rabattcode prominent, Deadline erzeugen\n' +
  '- Unten kleiner Footer-Hinweis: "Du bekommst diese Mail als Kunde von ' + setup.SHOP_NAME + '. Antworte mit STOP zum Abmelden."\n' +
  '- Mobiltaugliches HTML mit Inline-CSS, kein Spam-Vokabular (kein GRATIS!!!, keine Grossbuchstaben-Waende)\n' +
  'Antworte NUR mit validem JSON, ohne Markdown-Codeblock: {"betreff": "...", "html": "..."}';

return [{ json: { prompt, kampagnen_typ: typ.name } }];

const blocks = ($input.first().json.content) || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { betreff: 'Nur fuer dich 👀', html: text };
}
const setup = $('⚙️ Setup').first().json;
const maxEmpf = parseInt(setup.MAX_EMPFAENGER || 200);

// Nur Kunden mit Marketing-Einwilligung!
const kunden = (($('👥 Kundenliste holen').first().json.customers) || []).filter(k => {
  if (!k.email) return false;
  if (k.email_marketing_consent) return k.email_marketing_consent.state === 'subscribed';
  return k.accepts_marketing === true;
}).slice(0, maxEmpf);

if (setup.TEST_MODE === 'ja') {
  return [{ json: {
    empfaenger: setup.OWNER_EMAIL,
    betreff: '[TEST · Kampagne haette ' + kunden.length + ' Empfaenger] ' + daten.betreff,
    email_html: daten.html.split('{{VORNAME}}').join('Testkunde')
  }}];
}

return kunden.map(k => ({ json: {
  empfaenger: k.email,
  betreff: daten.betreff,
  email_html: daten.html.split('{{VORNAME}}').join(k.first_name || 'du')
}}));
